CREATE TYPE "ViagemStatus" AS ENUM ('PLANNED','OPEN_FOR_ALLOCATION','CLOSED_FOR_ALLOCATION','IN_TRANSIT','ARRIVED_BRAZIL','CANCELLED');
CREATE TYPE "MalaStatus" AS ENUM ('PLANNING','CLOSED','CHECKED_IN','ARRIVED_BRAZIL','RECEIVED','CANCELLED');
CREATE TABLE "Viajante"("id" TEXT PRIMARY KEY,"lojaId" TEXT NOT NULL,"nome" TEXT NOT NULL,"email" TEXT,"telefone" TEXT,"documento" TEXT,"observacoes" TEXT,"ativo" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "Viagem"("id" TEXT PRIMARY KEY,"lojaId" TEXT NOT NULL,"viajanteId" TEXT NOT NULL,"origem" TEXT NOT NULL,"destino" TEXT NOT NULL,"partidaEm" TIMESTAMP(3) NOT NULL,"chegadaPrevistaEm" TIMESTAMP(3) NOT NULL,"chegadaRealEm" TIMESTAMP(3),"status" "ViagemStatus" NOT NULL DEFAULT 'PLANNED',"periodoEnvio" TEXT NOT NULL DEFAULT 'MANHA',"observacoes" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "Mala"("id" TEXT PRIMARY KEY,"lojaId" TEXT NOT NULL,"viagemId" TEXT NOT NULL,"codigo" TEXT NOT NULL,"limitePesoKg" DECIMAL(8,3) NOT NULL DEFAULT 23,"status" "MalaStatus" NOT NULL DEFAULT 'PLANNING',"observacoes" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "VolumeLogistico"("id" TEXT PRIMARY KEY,"lojaId" TEXT NOT NULL,"malaId" TEXT NOT NULL,"codigo" TEXT NOT NULL,"taraKg" DECIMAL(8,3) NOT NULL DEFAULT .5,"observacoes" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "AlocacaoMala"("id" TEXT PRIMARY KEY,"lojaId" TEXT NOT NULL,"pedidoCompraItemId" TEXT NOT NULL,"malaId" TEXT NOT NULL,"volumeLogisticoId" TEXT NOT NULL,"quantidade" INTEGER NOT NULL,"pesoConteudoKg" DECIMAL(10,3) NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "RecebimentoMiami"("id" TEXT PRIMARY KEY,"lojaId" TEXT NOT NULL,"pedidoCompraItemId" TEXT NOT NULL,"quantidadeRecebida" INTEGER NOT NULL,"recebidoEm" TIMESTAMP(3) NOT NULL,"confirmadoPorId" TEXT NOT NULL,"observacao" TEXT,"atraso" BOOLEAN NOT NULL DEFAULT false,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "Viajante_lojaId_ativo_idx" ON "Viajante"("lojaId","ativo"); CREATE UNIQUE INDEX "Viajante_id_lojaId_key" ON "Viajante"("id","lojaId");
CREATE INDEX "Viagem_lojaId_status_idx" ON "Viagem"("lojaId","status"); CREATE INDEX "Viagem_lojaId_partidaEm_idx" ON "Viagem"("lojaId","partidaEm"); CREATE UNIQUE INDEX "Viagem_id_lojaId_key" ON "Viagem"("id","lojaId");
CREATE INDEX "Mala_lojaId_status_idx" ON "Mala"("lojaId","status"); CREATE UNIQUE INDEX "Mala_viagemId_codigo_key" ON "Mala"("viagemId","codigo"); CREATE UNIQUE INDEX "Mala_id_lojaId_key" ON "Mala"("id","lojaId");
CREATE INDEX "VolumeLogistico_lojaId_malaId_idx" ON "VolumeLogistico"("lojaId","malaId"); CREATE UNIQUE INDEX "VolumeLogistico_malaId_codigo_key" ON "VolumeLogistico"("malaId","codigo"); CREATE UNIQUE INDEX "VolumeLogistico_id_lojaId_key" ON "VolumeLogistico"("id","lojaId");
CREATE INDEX "AlocacaoMala_lojaId_malaId_idx" ON "AlocacaoMala"("lojaId","malaId"); CREATE UNIQUE INDEX "AlocacaoMala_pedidoCompraItemId_malaId_volumeLogisticoId_key" ON "AlocacaoMala"("pedidoCompraItemId","malaId","volumeLogisticoId");
CREATE INDEX "RecebimentoMiami_lojaId_pedidoCompraItemId_idx" ON "RecebimentoMiami"("lojaId","pedidoCompraItemId"); CREATE UNIQUE INDEX "PedidoCompraItem_id_lojaId_key" ON "PedidoCompraItem"("id","lojaId");
ALTER TABLE "Viajante" ADD FOREIGN KEY("lojaId") REFERENCES "Loja"("id"); ALTER TABLE "Viagem" ADD FOREIGN KEY("lojaId") REFERENCES "Loja"("id"); ALTER TABLE "Viagem" ADD FOREIGN KEY("viajanteId","lojaId") REFERENCES "Viajante"("id","lojaId"); ALTER TABLE "Mala" ADD FOREIGN KEY("lojaId") REFERENCES "Loja"("id"); ALTER TABLE "Mala" ADD FOREIGN KEY("viagemId","lojaId") REFERENCES "Viagem"("id","lojaId"); ALTER TABLE "VolumeLogistico" ADD FOREIGN KEY("lojaId") REFERENCES "Loja"("id"); ALTER TABLE "VolumeLogistico" ADD FOREIGN KEY("malaId","lojaId") REFERENCES "Mala"("id","lojaId") ON DELETE CASCADE; ALTER TABLE "AlocacaoMala" ADD FOREIGN KEY("lojaId") REFERENCES "Loja"("id"); ALTER TABLE "AlocacaoMala" ADD FOREIGN KEY("pedidoCompraItemId","lojaId") REFERENCES "PedidoCompraItem"("id","lojaId"); ALTER TABLE "AlocacaoMala" ADD FOREIGN KEY("malaId","lojaId") REFERENCES "Mala"("id","lojaId"); ALTER TABLE "AlocacaoMala" ADD FOREIGN KEY("volumeLogisticoId","lojaId") REFERENCES "VolumeLogistico"("id","lojaId"); ALTER TABLE "RecebimentoMiami" ADD FOREIGN KEY("lojaId") REFERENCES "Loja"("id"); ALTER TABLE "RecebimentoMiami" ADD FOREIGN KEY("pedidoCompraItemId","lojaId") REFERENCES "PedidoCompraItem"("id","lojaId"); ALTER TABLE "RecebimentoMiami" ADD FOREIGN KEY("confirmadoPorId") REFERENCES "Usuario"("id");
